import{_ as e,c as a,o,b as t}from"./app.46c22443.js";const b=`{"title":"Partners","description":"","frontmatter":{"title":"Partners","subtitle":"Companies we've collaborated with","date":"2021-01-01T00:00:00.000Z"},"headers":[{"level":2,"title":"Educational content","slug":"educational-content"},{"level":3,"title":"SkillBox video course","slug":"skillbox-video-course"},{"level":2,"title":"Web-apps","slug":"web-apps"},{"level":3,"title":"Playtronica web experience","slug":"playtronica-web-experience"},{"level":2,"title":"Music video production","slug":"music-video-production"},{"level":3,"title":"tsoop","slug":"tsoop"}],"relativePath":"academy/partners/index.md"}`,r={},i=t('<p>Chromatone is ready to be used in a multitude of music educational products like courses, workshops, posters, stickers and, of course, web-apps. We are ready to get involved in any of these directions and we are glad to meet new companies to collaborate with.</p><h2 id="educational-content" tabindex="-1">Educational content <a class="header-anchor" href="#educational-content" aria-hidden="true">#</a></h2><blockquote><p>We are open for educational content collaborations. Chromatone is the platform to produce it for different audiences. In HQ and with music theory expertise.</p></blockquote><h3 id="skillbox-video-course" tabindex="-1">SkillBox video course <a class="header-anchor" href="#skillbox-video-course" aria-hidden="true">#</a></h3><p>In 2021 we&#39;ve been working with the educational platform called <a href="https://skillbox.ru" class="external-link" target="_blank" rel="noopener noreferrer">SkillBox</a> on an <a href="./../../academy/materials/ru/skillbox/">11 modules video course</a> that leads beginners from basic light and sound physics through intervals and scales up to the level of music composition techniques. Each module consists of 3-5 lessons 15-30 minutes each. We go through all the topics with the use of Chromatone web-apps and different instruments. Learners get custom designed sticker sheets from the company by mail and have some instrumental videos to shoot for the homework.</p><h2 id="web-apps" tabindex="-1">Web-apps <a class="header-anchor" href="#web-apps" aria-hidden="true">#</a></h2><blockquote><p>The open-source parts of Chromatone are ready to use in a multitude of variegated educational and emotional experiences. And building them makes Chromatone even better!</p></blockquote><h3 id="playtronica-web-experience" tabindex="-1">Playtronica web experience <a class="header-anchor" href="#playtronica-web-experience" aria-hidden="true">#</a></h3><p>In 2022 we started our web-app collaboration with <a href="https://playtronica.com" class="external-link" target="_blank" rel="noopener noreferrer">Playtronica</a>. They&#39;re building MIDI controllers and we&#39;re building an interactive audio-visual playground web application together - the <a href="./../../apps/experiment/touchme/">TouchMe Experience</a>.</p><h2 id="music-video-production" tabindex="-1">Music video production <a class="header-anchor" href="#music-video-production" aria-hidden="true">#</a></h2><h3 id="tsoop" tabindex="-1">tsoop <a class="header-anchor" href="#tsoop" aria-hidden="true">#</a></h3><p><a href="https://tsoop.ru" class="external-link" target="_blank" rel="noopener noreferrer">tsoop.ru</a> is an improvisational electronic music project with visualizations based on Chromatone system. There&#39;s a couple of albums published, but the main focus is on live collaborative music events. It&#39;s the research about what else can we can perform together. \u{1F941}</p>',12),n=[i];function s(l,c,d,h,p,u){return o(),a("div",null,n)}var f=e(r,[["render",s]]);export{b as __pageData,f as default};
